# Modificación del Orquestador - Extracción Automática de Archivos

## Análisis
Necesito modificar `/home/agentes/orchestrator.js` para agregar:
1. Función `parseFileBlocks()` - detectar bloques con formato ```filepath:/ruta/al/archivo
2. Función `writeExtractedFiles()` - escribir archivos usando fs.writeFile
3. Integración en el flujo de ejecución de agentes

## Implementación

```javascript
// Agregar al inicio del archivo después de los imports
const fs = require('fs').promises;
const path = require('path');

// Nueva función para extraer bloques de archivos
function parseFileBlocks(responseText) {
    const blocks = [];
    const regex = /```filepath:(\/[^\n]+)\n([\s\S]*?)```/g;
    let match;

    while ((match = regex.exec(responseText)) !== null) {
        const filePath = match[1].trim();
        const content = match[2];

        blocks.push({
            path: filePath,
            content: content
        });
    }

    return blocks;
}

// Nueva función para escribir archivos extraídos
async function writeExtractedFiles(fileBlocks, jobId) {
    const results = [];

    for (const block of fileBlocks) {
        try {
            // Validar que la ruta esté dentro del directorio permitido
            const normalizedPath = path.normalize(block.path);
            const baseDir = '/home/agentes';

            if (!normalizedPath.startsWith(baseDir)) {
                throw new Error(`Ruta no permitida: ${normalizedPath}`);
            }

            // Crear directorio si no existe
            const dir = path.dirname(normalizedPath);
            await fs.mkdir(dir, { recursive: true });

            // Escribir archivo
            await fs.writeFile(normalizedPath, block.content, 'utf8');

            results.push({
                path: normalizedPath,
                status: 'success',
                size: block.content.length
            });

            console.log(`[${jobId}] Archivo escrito: ${normalizedPath} (${block.content.length} bytes)`);

        } catch (error) {
            results.push({
                path: block.path,
                status: 'error',
                error: error.message
            });

            console.error(`[${jobId}] Error escribiendo ${block.path}:`, error.message);
        }
    }

    return results;
}

// Modificar la función executeAgent existente
async function executeAgent(agentName, task, jobId) {
    try {
        jobs[jobId].status = 'ejecutando';
        jobs[jobId].agente_activo = agentName;
        jobs[jobId].tiempo_inicio = Date.now();

        console.log(`[${jobId}] Ejecutando agente ${agentName}...`);

        const agentModule = agents[agentName];
        if (!agentModule) {
            throw new Error(`Agente ${agentName} no encontrado`);
        }

        const result = await agentModule.execute(task);

        // NUEVA FUNCIONALIDAD: Extraer y escribir archivos
        if (result && typeof result === 'string') {
            const fileBlocks = parseFileBlocks(result);

            if (fileBlocks.length > 0) {
                console.log(`[${jobId}] Encontrados ${fileBlocks.length} bloques de archivo para escribir`);

                const writeResults = await writeExtractedFiles(fileBlocks, jobId);

                // Agregar resultados de escritura al job
                jobs[jobId].archivos_escritos = writeResults;

                const successCount = writeResults.filter(r => r.status === 'success').length;
                const errorCount = writeResults.filter(r => r.status === 'error').length;

                console.log(`[${jobId}] Archivos escritos: ${successCount} exitosos, ${errorCount} errores`);
            }
        }

        jobs[jobId].resultado = result;
        jobs[jobId].status = 'completado';
        jobs[jobId].tiempo_fin = Date.now();
        jobs[jobId].duracion = jobs[jobId].tiempo_fin - jobs[jobId].tiempo_inicio;

        console.log(`[${jobId}] Agente ${agentName} completado en ${jobs[jobId].duracion}ms`);

        return result;

    } catch (error) {
        jobs[jobId].status = 'error';
        jobs[jobId].error = error.message;
        jobs[jobId].tiempo_fin = Date.now();
        jobs[jobId].duracion = jobs[jobId].tiempo_fin - jobs[jobId].tiempo_inicio;

        console.error(`[${jobId}] Error en agente ${agentName}:`, error);
        throw error;
    }
}

