# Mejora del Sistema de Escritura de Archivos - Logging y Manejo de Errores

## Análisis
Necesito mejorar el sistema de escritura automática de archivos en `/home/agentes/orchestrator.js` agregando:
1. **Logging detallado**: registrar escrituras exitosas y fallidas
2. **Manejo robusto de errores**: permisos, rutas inexistentes, etc.
3. **Continuidad del flujo**: no fallar la tarea completa por errores de escritura

## Implementación

```javascript
// Agregar al inicio del archivo después de las importaciones
const fs = require('fs').promises;
const path = require('path');

// Función mejorada para logging de archivos
function logFileOperation(operation, filePath, agentName, success, error = null) {
    const timestamp = new Date().toISOString();
    const logEntry = {
        timestamp,
        operation,
        file: filePath,
        agent: agentName,
        success,
        error: error?.message || null
    };

    console.log(`[FILE-${operation.toUpperCase()}] ${timestamp} | ${agentName} | ${filePath} | ${success ? 'SUCCESS' : 'FAILED'}`);
    if (error) {
        console.error(`[FILE-ERROR] ${error.message}`);
    }
}

// Función mejorada para crear directorios si no existen
async function ensureDirectoryExists(filePath) {
    try {
        const dir = path.dirname(filePath);
        await fs.access(dir);
        return true;
    } catch (error) {
        try {
            await fs.mkdir(dir, { recursive: true });
            logFileOperation('MKDIR', path.dirname(filePath), 'system', true);
            return true;
        } catch (mkdirError) {
            logFileOperation('MKDIR', path.dirname(filePath), 'system', false, mkdirError);
            return false;
        }
    }
}

// Función mejorada para escribir archivos con manejo de errores
async function writeExtractedFiles(response, agentName) {
    const files = parseFileBlocks(response);
    const results = {
        written: [],
        failed: [],
        total: files.length
    };

    if (files.length === 0) {
        return results;
    }

    console.log(`[FILE-EXTRACT] Detectados ${files.length} archivos para escribir desde agente ${agentName}`);

    for (const file of files) {
        const { path: filePath, content } = file;

        try {
            // Validar ruta absoluta
            if (!path.isAbsolute(filePath)) {
                throw new Error(`Ruta debe ser absoluta: ${filePath}`);
            }

            // Validar que la ruta esté dentro de /home/agentes/
            const basePath = '/home/agentes/';
            if (!filePath.startsWith(basePath)) {
                throw new Error(`Acceso denegado. Solo se permite escribir en ${basePath}`);
            }

            // Crear directorio si no existe
            const dirCreated = await ensureDirectoryExists(filePath);
            if (!dirCreated) {
                throw new Error(`No se pudo crear el directorio para ${filePath}`);
            }

            // Crear backup del archivo existente
            try {
                await fs.access(filePath);
                const backupPath = `${filePath}.backup.${Date.now()}`;
                await fs.copyFile(filePath, backupPath);
                logFileOperation('BACKUP', backupPath, agentName, true);
            } catch (accessError) {
                // Archivo no existe, no necesita backup
            }

            // Escribir archivo
            await fs.writeFile(filePath, content, 'utf8');

            // Verificar escritura
            const written = await fs.readFile(filePath, 'utf8');
            if (written !== content) {
                throw new Error('Verificación de escritura falló');
            }

            logFileOperation('WRITE', filePath, agentName, true);
            results.written.push(filePath);

        } catch (error) {
            logFileOperation('WRITE', filePath, agentName, false, error);
            results.failed.push({
                path: filePath,
                error: error.message
            });

            // Continuar con el siguiente archivo sin fallar
            continue;
        }
    }

    // Log resumen
    console.log(`[FILE-SUMMARY] ${agentName} | Escritos: ${results.written.length} | Fallidos: ${results.failed.length}`);

    return results;
}

// Función para parsear bloques de archivos (mejorada)
function parseFileBlocks(text) {
    const files = [];
    const regex = /```filepath:([^\n]+)\n([\s\S]*?)```/g;
    let match;

    while ((match = regex.exec(text)) !== null) {
        const filePath = match[1].trim();
        const content = match[2];

        if (filePath && content) {
            files.push({
                path: filePath,
                content: content
            });
        }
    }

    return files;
}

// Modificar la función executeTask para incluir escritura de archivos
async function executeTask(taskData) {
    const { project, description, assignedAgent } = taskData;
    const jobId = Date.now().toString();

    jobs[jobId] = {
        id: jobId,
        project,
        description,
        agent: assignedAgent,
        status: 'EN COLA',
        created: new Date(),
        started: null,
        completed: null,
        result: null,
        fileResults: null // Agregar resultados de archivos
    };

    try {
        jobs[jobId].status = 'EJECUTANDO';
        jobs[jobId].started = new Date();

        const result = await callAgent(assignedAgent, description, project);

        // Procesar escritura de archivos
        const fileResults = await writeExtractedFiles(result, assignedAgent);

        jobs[jobId].status = 'COMPLETADO';
        jobs[jobId].completed = new Date();
        jobs[jobId].result = result;
        jobs[jobId].fileResults = fileResults;

        // Log final con información de archivos
        const duration = jobs[jobId].completed - jobs[jobId].started;
        console.log(`[TASK-COMPLETE] ${jobId} | ${assignedAgent} | ${duration}ms | Files: ${fileResults.written.length}/${fileResults.total}`);

        return jobId;

    } catch (error) {
        jobs[jobId].status = 'ERROR';
        jobs[jobId].completed = new Date();
        jobs[jobId].result = `Error: ${error.message}`;
        jobs[jobId].fileResults = { written: [], failed: [], total: 0 };

        console.error(`[TASK-ERROR] ${jobId} | ${assignedAgent} | ${error.message}`);
        return jobId;
    }
}

// Agregar endpoint para obtener información de archivos escritos
app.get('/files/:jobId', (req, res) => {
    const { jobId } = req.params;
    const job = jobs[jobId];

    if (!job) {
        return res.status(404).json({ error: 'Job no encontrado' });
    }

    res.json({
        jobId,
        agent: job.agent,
        fileResults: job.fileResults || { written: [], failed: [], total: 0 }
    });
});
```

## Características Implementadas

### 1. **Logging Detallado**
- Timestamp de cada operación
- Agente responsable
- Ruta del archivo
- Estado (SUCCESS/FAILED)
- Mensajes de error específicos

### 2. **Manejo Robusto de Errores**
- Validación de rutas absolutas
- Restricción de escritura a `/home/agentes/`
- Creación automática de directorios
- Backup automático de archivos existentes
- Verificación post-escritura

### 3. **Continuidad del Flujo**
- Errores de archivo no fallan la tarea completa
- Procesamiento individual de cada archivo
- Resumen de resultados al final
- Estado detallado por archivo

### 4. **Nuevas Funcionalidades**
- Endpoint `/files/:jobId` para consultar resultados de archivos
- Backups automáticos con timestamp
- Logs estructurados para auditoría

## Seguridad Implementada

1. **Validación de rutas**: Solo se permite escritura en `/home/agentes/`
2. **Rutas absolutas**: Previene path traversal
3. **Backups automáticos**: Recuperación ante errores
4. **Logging completo**: Auditoría de todas las operaciones

